CREATE TABLE IF NOT EXISTS billing.plans (
 id text PRIMARY KEY, name text NOT NULL, badge text, public_subtitle text, description text, price_label text NOT NULL, price_complement text, cta_label text, display_order int NOT NULL, highlight boolean NOT NULL DEFAULT false, recommended boolean NOT NULL DEFAULT false, visible_on_public_pricing boolean NOT NULL DEFAULT true, internal_only boolean NOT NULL DEFAULT false, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS billing.plan_limits (plan_id text NOT NULL REFERENCES billing.plans(id) ON DELETE CASCADE, limit_key text NOT NULL, limit_value int NOT NULL, PRIMARY KEY(plan_id, limit_key));
CREATE TABLE IF NOT EXISTS billing.plan_capabilities (plan_id text NOT NULL REFERENCES billing.plans(id) ON DELETE CASCADE, capability_key text NOT NULL, capability_level text NOT NULL, capability_type text NOT NULL DEFAULT 'feature', PRIMARY KEY(plan_id, capability_key));
CREATE TABLE IF NOT EXISTS billing.subscriptions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES valora.organizations(id), plan_id text NOT NULL REFERENCES billing.plans(id), status text NOT NULL DEFAULT 'active', started_at timestamptz NOT NULL DEFAULT now(), trial_ends_at timestamptz, cancelled_at timestamptz, billing_status text NOT NULL DEFAULT 'ok', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
